INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1001, '弓を引き絞る', '赤', '弓のみ', 'パッシブ', '6秒ごとに敵部隊へ武攻ダメージ 115%【250%】を与える。自身の通常攻撃ダメージがクリティカルとなった場合、即座に発動し時間がリセットされます。（2秒に1回まで発動可能）', 1001);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1002, '絶世の風華', '赤', NULL, 'パッシブ', '主将が与える全ダメージが9%【18%】増加します。（知力補正）', 1002);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1003, '短矢軽弓', '赤', '弓のみ', 'パッシブ', '部隊は、距離が2を超える部隊からの全ダメージを1%【10%】の確率で回避可能です。弓兵であり、かつ非戦闘状態の場合、部隊の移動速度が30【120】増加します。', 1003);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1004, '乾坤逆転', '赤', NULL, 'パッシブ', '部隊が通常攻撃を受けた際、16%【25%】の確率（刀兵の場合は追加で5%上昇）で、敵の通常攻撃ダメージが自身の兵力回復（ダメージ値分）へ変換されます。', 1004);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1005, '堅壁固守', '赤', NULL, 'パッシブ', '戦闘に進入後、2秒ごとに部隊が受ける全ダメージが2％減少し、最大1【10】層まで重複可能。この効果は移動するたびにリセットされる。', 1005);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1006, '英姿あふれる', '赤', NULL, 'パッシブ', '戦闘に進入後、部隊が受ける全ダメージが16.5%【30%】減少し、その後10秒ごとに減少効果が4%ずつ低下する。最低5%まで下がり、戦闘状態を離れるまで継続する。', 1006);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1007, '梟姫', '赤', NULL, 'パッシブ', '戦闘に進入後、6秒ごとに敵部隊に武攻ダメージ 120%【300%】を与える。対象部隊がデバフ状態の場合、この攻撃のクリティカル率が22%【40%】上昇する。', 1007);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1008, '毒蒺藜', '赤', NULL, 'パッシブ', '部隊がダメージを受けた際、21％【30%】の確率で敵部隊を【中毒】状態（ダメージ率90% 【180%】）にする。6秒間持続し、ダメージを与えた部隊ごとに2秒につき1回のみ判定される。', 1008);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1009, '応急手当', '赤', NULL, '能動', '21%【30%】の確率で発動し、部隊の兵力を一定量回復（回復率170%【350%】知力補正）', 1009);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1010, '破陣', '赤', NULL, '能動', '21%【30%】の確率で発動し、敵部隊の全武将を【属性減少】状態にし、胆力-16【-25】6秒間持続', 1010);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1011, '吏清らかにして政明らか', '赤', NULL, 'パッシブ', '主政官に任命されている場合、食糧・木材・石材・鉄鉱石の産出量が1.2%【3%】増加（内政補正）', 1011);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1012, '豪傑の広範募集', '赤', NULL, 'パッシブ', '募兵使に任命されている場合、予備兵の徴兵消耗が5.5%【10%】減少', 1012);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1013, '怒りを制す', '赤', '弓以外', 'パッシブ', '自身の知力が胆力を上回る場合、部隊が受ける知攻ダメージが7%【25％】減少し、怒気5ごとにさらに1%減少。胆力が知力を上回る場合、部隊が受ける武攻ダメージが7%【25%】減少し、怒気5ごとにさらに1%減少', 1013);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1014, '深謀遠慮', '赤', '弓以外', 'パッシブ', '戦闘開始後、自身の与ダメージが2秒ごとに1%上昇し、最大12%【30%】まで上昇可能。戦闘離脱時にリセットされる。', 1014);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1015, '兵糧断ちの策', '赤', NULL, '能動', '31％【40%】の確率で発動し、敵部隊に知攻ダメージ 115%【250%】を与え、さらに【治療禁止】状態にし、4秒間持続', 1015);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1016, '日を貫く矢', '赤', '弓のみ', 'パッシブ', '自身のクリティカル率+9%【+18%】対象部隊の高さが自分より高い場合、さらにクリティカル率+12%【+30%】', 1016);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1017, '背水の陣', '赤', '弓以外', 'パッシブ', '部隊が移動していない状態で、2秒間内にダメージ（0以外）を受けるたび、異なる敵部隊1つごとに、部隊の怒気が1.5回復される。さらに戦闘突入前40秒間、2秒ごとに追加2.3【5】怒気を回復', 1017);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1018, '反旗を翻し一撃', '赤', '弓以外', 'パッシブ', '部隊被ダメージ時、【円形範囲】内の敵部隊に反撃マークを付与。戦闘離脱時解除。反撃マーク付き部隊へのダメージ時、追加で武攻ダメージ 58%【130%】を与えマークを解除。', 1018);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1019, '国の干城', '赤', NULL, 'パッシブ', '部隊が受ける全ダメージが5.8%【13%】減少', 1019);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1020, '高地の利', '赤', '弓のみ', 'パッシブ', '部隊が自身より高さの低い敵部隊に与える全ダメージが12%【30%】増加', 1020);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1021, '計略窮す', '赤', NULL, 'パッシブ', '部隊がダメージを受けた時、7%【25%】の確率で敵全武将を【計略窮す】状態にし、2秒間持続。各ダメージ元部隊は2秒ごとに1回判定。【計略窮す】＝アクティブスキル発動不可（塗り替え不可）', 1021);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1022, '勢いに乗じて前進', '赤', NULL, 'パッシブ', '自身が連鎖スキルを発動するたびに、自身の連鎖スキルダメージ（知力補正）が6.5%【20%】上昇、2秒間持続。最大4回まで重複', 1022);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1023, '鋒鋩鋭進', '赤', NULL, 'パッシブ', '自身が与える通常攻撃ダメージが35%【80%】上昇', 1023);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1024, '虎射の威', '赤', NULL, 'パッシブ', '自身の固有スキルが異なる敵部隊にダメージを与えるたび、自身のクリティカル率+5.5【10%】2秒間持続。', 1024);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1025, '龍胆', '赤', NULL, '連鎖', '通常攻撃後、30%の確率で敵軍部隊に武攻ダメージ 65%【200%】を与え、固有連鎖スキルの発動率を+1%【+10%】する。この効果は重複可能で、持続時間は4秒。', 1025);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1026, '三軍に冠たる勇', '赤', NULL, '連鎖', '通常攻撃後、26%【35%】の確率で敵部隊に武攻ダメージ 130%【220%】を与え、敵主将または副将のアクティブスキル発動率を6%減少させる。効果は2秒間持続。', 1026);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1027, '戦うほど勇ましくなる', '赤', NULL, '能動', '25%【70％】の確率で発動し、敵部隊に武攻ダメージ 115%を与え、【武力増加】状態を獲得、武力が10増加、4秒間持続。重複可能で、重複するたびに全ての層の状態持続時間が4秒にリセットされる。5層に達する。', 1027);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1028, '全民兵となる', '赤', NULL, '能動', '26%【35%】の確率で発動し、部隊の兵力を一定回復（回復率110%【200%】知力補正）。2秒以内にダメージを受けた場合、ダメージを与えた部隊1隊ごとに回復率が23%【50%】追加され、最大450%まで増加', 1028);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1029, '軍神の采配', '赤', NULL, '能動', '21.5%【35%】の確率で発動し、敵部隊に知攻ダメージ 90%【270%】を与える。対象兵種を克制（有利兵種の場合）している場合、21.5%【35%】の確率で再度発動し、最大1回まで発動可能', 1029);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1030, '謀を討つ', '赤', NULL, '能動', '21%【30%】の確率で発動し、敵部隊に知攻ダメージ 165%【300%】を与え、さらにその主将の武力・知力を23【50】減少させ、4秒間持続。', 1030);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1031, '万夫も開かず', '赤', '刀兵のみ', '能動', '21%【30%】の確率で発動し、敵部隊に武攻ダメージ 110%【200%】を与え、部隊に【被ダメージ軽減】状態を付与する。この状態中、非対象部隊から受ける全ダメージが11%【20%】減少し、4秒間持続', 1031);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1032, '休戦し民を養う', '赤', NULL, '能動', '26%【35％】の確率で発動し、まず部隊の【治癒】状態を処理した後、部隊に【治癒】状態（回復率77%【140%】知力補正）を付与する。6秒間持続。', 1032);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1033, '力を蓄えて一気に発する', '赤', '弓以外', '能動', '32%【50%】の確率で発動し、【準備状態】に入り、6秒後に敵に知攻ダメージ 345%【750%】を与える。(目標切替、束縛、目標消失などで準備状態が中断）', 1033);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1034, '文武両道', '赤', NULL, '能動', '35%の確率で発動し、敵に武攻ダメージ 65%【200%】および知攻ダメージ 90%【270%】を与える。', 1034);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1035, '切り札', '赤', NULL, '能動', '30％の確率で発動し、敵部隊に武攻ダメージ 105%【285%】を与え、【武攻ダメージ軽減】状態にする。この状態中、与える武攻ダメージが5.5%【10%】減少し、4秒間持続', 1035);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1036, '四面楚歌', '赤', NULL, '能動', '12％【30%】の確率で発動し、敵部隊を【恐慌】状態にする。持続時間は4秒。恐慌：状態持続中、1部隊の攻撃を受けるごとに全武将の武力・胆力・知力-10、2秒間持続。最大50まで減少。重複・置換不可。', 1036);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1037, '挑発', '赤', '弓以外', '能動', '35%の確率で発動し、敵部隊を【挑発】状態にし、さらにその部隊が対象部隊から受けるダメージを21%【30%】減少させる。持続時間は4秒。挑発：目標固定', 1037);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1038, '力を溜めて一撃', '赤', NULL, '能動', '31%【40%】の確率で発動し、【準備状態】に進入する。4秒後、敵に武攻ダメージ 330%【600%】を与える。(目標切替、束縛、目標消失などで準備状態が中断）', 1038);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1039, '鬼神乱舞', '赤', NULL, '能動', '22%【40%】の確率で発動し、敵部隊に武攻ダメージ 90%【180%】を与える。[自身の武力]-[目標の主将の武力]が50を超える場合、ダメージ率がさらに80%【170%】加算され、かつ部隊が【免疫】状態を獲得する。持続時間2秒。免疫：デバフ状態の影響を受けない。', 1039);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1040, '枯木に花', '赤', NULL, '能動', '30％の確率で発動し、部隊の兵力を回復する。回復量=直前2秒間の兵力損失x11%【20%】xダメージを与えた敵部隊数（最大4部隊）', 1040);
