INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1042, '陣を突き軍を衝く', '赤', '馬のみ', '能動', '25％の確率で発動し。敵部隊に武攻ダメージ 198%【360%】を与え、かつ部隊が【強攻】状態になる。持続4秒。強攻：武攻ダメージは敵の30％胆力を無視する。', 1042);
