INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1044, '十面埋伏', '赤', NULL, '能動', '21%【30%】の確率で発動し、敵軍部隊に知攻ダメージ 145%【370%】を与える。敵軍部隊の士気が100以下の場合、【鈍足】状態となり、速度 -44【-80】、持続時間4秒。さらに士気を2ポイント減少させる。', 1044);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1045, '白頭不離', '赤', NULL, '能動', '30％の確率で発動し、自部隊が【治癒禁止】状態（持続2秒）になることを代償に、部隊に【被ダメージ軽減】状態を付与し、受ける全ダメージを12%【30%】減少。持続時間は4秒。', 1045);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1046, '虚に乗じて入る', '赤', NULL, '能動', '25%の確率で発動し、敵軍部隊に知攻ダメージ 130%【400%】を与える。', 1046);
