INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1053, '起死回生', '紫', NULL, '能動', '21%【30%】の確率で発動し、部隊の兵力を一定量回復（回復率65%【200%】知力補正）。兵力が40%未満の場合、回復率がさらに55%【100%】上昇。', 1053);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1054, '内助賢才', '紫', NULL, '能動', '21%【30%】の確率で発動し、主将に【属性強化】状態を付与し、最高の能力値が32【50】上昇。4秒間持続', 1054);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1055, '狂瀾覆し', '紫', NULL, '能動', '21%【30%】の確率で発動し、敵部隊に武攻ダメージ 80%【170%】を与える。このダメージは敵の23%【50%】胆力を無視。', 1055);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1056, '論戦', '紫', NULL, '能動', '30%の確率で発動し、敵部隊に知攻ダメージ 125%【260%】を与える。15回目以降、このスキルのダメージ率は100%減少し、退場まで持続。', 1056);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1057, '戦を請う', '紫', NULL, '能動', '22%【40%】の確率で発動し、自身に【ダメージ増加】状態を付与、与える全ダメージが24%【60%】上昇。2秒間持続。', 1057);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1058, '火攻乱敵', '紫', NULL, '能動', '30%の確率で発動し、敵部隊に知攻ダメージ 35%【80%】を与え、さらに地形を【燃焼】（ダメージ率45%【90%】）状態にし、4秒間持続。', 1058);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1059, '天下に独り戦う', '紫', NULL, '能動', '11%【29%】の確率で発動し、自身の【円形範囲】内の2部隊の敵部隊を【挑発】状態にし、2秒間持続する。', 1059);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1060, '矢雨潰敵', '紫', NULL, '能動', '26%【35%】の確率で発動し、敵部隊に武攻ダメージ 100%【190%】を与え、さらに【鈍足】状態にし、移動速度が7%【25%】減少。4秒間持続', 1060);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1061, '見抜き', '紫', NULL, '能動', '11%【29%】の確率で発動し、部隊に【見抜き】状態を付与し、いずれかのアクティブスキルによるダメージを2秒間受けた後、この状態が解除される。(見抜き：アクティブスキルの被ダメ大幅減少）', 1061);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1062, '力借りて力を打つ', '紫', NULL, '能動', '20%【65%】の確率で発動し、部隊内の他の武将を【通常攻撃不可】状態にし、2秒間持続。自身は通常攻撃をもう1回追加で行える。', 1062);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1063, '寡兵制衆', '紫', NULL, '能動', '26%【35%】の確率で発動し、敵部隊に武攻ダメージ 90%【180%】を与える。自軍の兵力が敵部隊兵力より少ない場合、ダメージ率 120%【255%】まで上昇。', 1063);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1064, '先制', '紫', NULL, '能動', '26％【35%】の確率で発動し、敵部隊に武攻ダメージ 70%【160%】を与え、戦闘開始から100秒間はこのスキルのダメージ率が95%【230%】に上昇。', 1064);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1065, '潰敵', '紫', NULL, '能動', '30%の確率で発動し、敵を【潰走】状態にし、ダメージ率40%【85%】2秒間持続。', 1065);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1066, '商聖', '紫', NULL, 'パッシブ', '交易官を担当する場合、市場取引の比率が2.5%【7%】増加する。', 1066);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1067, '博識多才', '紫', NULL, 'パッシブ', '生産系の内政官を担当すると、該当する基礎資源算出が650【2000】増加する。', 1067);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1068, '爆破', '紫', '兵器含む', 'パッシブ', '部隊が建築物に与える全ダメージが31%【85%】増加する。', 1068);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1069, '自守の心', '紫', NULL, 'パッシブ', '自身の知力+1【+10】、さらに部隊が37%【100%】の確率で【挑発】状態を無効化', 1069);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1070, '連撃', '紫', NULL, '能動', '25%【52%】の確率で発動し、自身に【連撃】状態を付与。2秒間持続', 1070);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1071, '軍制厳然', '紫', NULL, 'パッシブ', '部隊が受ける連鎖ダメージが9%【27%】減少する。', 1071);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1072, '百戦錬磨', '紫', NULL, 'パッシブ', '自身が怒気技を発動すると、部隊は16%【52%】の確率で【ダメージ無効】状態となり、4秒間持続する。', 1072);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1073, '屯兵', '紫', NULL, 'パッシブ', '戦闘開始後、2秒ごとに自身の胆力ｘ12.5%【26%】の兵力を回復する。', 1073);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1074, '奇策', '紫', NULL, 'パッシブ', '部隊の全武将がアクティブスキルを発動した際、23%【50%】の確率でその一撃のダメージが7%【25%】増加する。', 1074);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1075, '済世の略', '紫', NULL, 'パッシブ', '自身が通常攻撃を2回行うごとに、自身の武力ｘ13%【40％】の兵力を回復する', 1075);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1076, '百出', '紫', NULL, 'パッシブ', '自身のアクティブスキル発動率 +3.5%【+8%】', 1076);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1077, '筆を捨て軍に従う', '紫', NULL, 'パッシブ', '戦闘開始後、自身の武力が基礎知力ｘ8%【26%】増加する。', 1077);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1078, '一撃制圧', '紫', NULL, 'パッシブ', '自身のクリティカル率+3%【12%】', 1078);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1079, '敵鋒挫き', '紫', NULL, 'パッシブ', '部隊が受けるアクティブスキルダメージが6%【15%】減少する。', 1079);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1080, '強弩猛射', '紫', '弓のみ', 'パッシブ', '部隊が距離2以下の目標に与える全ダメージが12%【30%】増加する。', 1080);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1081, '三軍奮戦', '紫', '弓以外', 'パッシブ', '部隊壊滅時,【円形範囲】内の最大3敵部隊に物理ダメージ 700%【2500%】、100秒以内に兵力50%以上損失時+320%【+950%】。出撃時兵力基準。NPC戦：傷病率-50%/プレイヤー戦：傷病率-5%', 1081);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1082, '寸土不退', '紫', NULL, 'パッシブ', '戦闘開始後、2秒ごとに部隊を受ける全ダメージが1%減少し、最大3%【12%】まで減少する。移動のたびにダメージ減少効果はリセットされる。', 1082);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1083, '塞外平定', '紫', NULL, '連鎖', '通常攻撃後、25%の確率で敵部隊に武攻ダメージ 85%【220%】を与える。自身が【連撃】状態の場合、このスキルの発動確率がさらに5%上昇。', 1083);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1084, '八方馬踏', '紫', NULL, '連鎖', '通常攻撃後、25%の確率で敵部隊に武攻ダメージ 75%【210%】を与える。対象兵種を克服している場合、対象部隊を【治療禁止】状態にし、4秒間持続。', 1084);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1085, '帝の親征', '紫', NULL, '連鎖', '通常攻撃後、25%の確率で敵部隊に知攻ダメージ 75%【210%】を与え、さらに敵の怒気を5減少させる。', 1085);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1086, '孤勇', '青', NULL, 'パッシブ', '自部隊と敵部隊がいずれも他部隊と交戦していない時、自部隊が与える武攻ダメージが22%【40%】増加し、被武攻ダメージが39%【30%】増加する。', 1086);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1087, '魯班鋸', '青', NULL, 'パッシブ', '伐採官担当時、木材産出量が2.3%【5%】上昇する。（内政補正）', 1087);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1088, '城砕き', '青', NULL, 'パッシブ', '自身が建築物に与える全ダメージが40%【130%】上昇', 1088);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1089, '旗揚げ', '青', NULL, '連鎖', '通常攻撃後、25%の確率で敵部隊に武攻ダメージ 60%【195％】を与える。', 1089);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1090, '金剛', '青', NULL, 'パッシブ', '部隊が受ける全ダメージが2.4%【6%】減少', 1090);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1091, '委壌', '青', NULL, '能動', '35%の確率で発動し、主将が与える全ダメージが13%【40%】上昇、2秒間持続', 1091);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1092, '暗殺', '青', NULL, '能動', '30%の確率で発動し、武攻ダメージ 45%【180】を与え、このダメージは20%の確率でクリティカルになる。', 1092);
